const raw = $json.text || $json.content || $json.message.content || $json.response || '{}';
let parsed;
try {
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  return [{ json: { valid: false, reason: 'Invalid JSON from LLM', raw } }];
}

const required = ['oktaGroups', 'googleGroups', 'slackChannels', 'jiraRoles'];
const missing = required.filter((k) => !(k in parsed));
if (missing.length) {
  return [{ json: { valid: false, reason: `Missing fields: ${missing.join(', ')}`, parsed } }];
}

return [{ json: { valid: true, accessDecision: parsed } }];

const employee = $node['Normalize Employee Data'].json;
const accessDecision = $node['Validate AI Output'].json.accessDecision;
return [{
  json: {
    ...employee,
    accessDecision,
    executionId: `onboard-${employee.employeeId}-${Date.now()}`
  }
}];

