return [{
  json: {
    executionId: $node['Assemble Provisioning Payload'].json.executionId,
    employeeId: $node['Normalize Employee Data'].json.employeeId,
    email: $node['Normalize Employee Data'].json.email,
    status: 'success',
    checks: $input.first().json.checks,
    systems: ['okta', 'google-workspace', 'slack', 'jira'],
    timestamp: new Date().toISOString()
  }
}];

const items = $input.all();

// Find any error payload if one exists
const errorItem = items.find(item => item.json?.error || item.json?.status === "failure");

// Search all input items for successful MCP actions
const userInvited = items.some(item => item.json?.action === "invited_user");
const assignedRoles = items.some(item => item.json?.action === "assigned_roles");
const createdWorkspace = items.some(item => item.json?.action === "created_workspace_user");
const createdUser = items.some(item => item.json?.action === "created_user");

// Optional: count reused resources as success too
const reusedUser = items.some(item => item.json?.action === "reused_existing_user");
const reusedWorkspace = items.some(item => item.json?.action === "reused_existing_workspace_user");

const userProvisioned = createdUser || reusedUser;
const workspaceProvisioned = createdWorkspace || reusedWorkspace;

const success = userInvited && assignedRoles && workspaceProvisioned && userProvisioned;

return [
  {
    json: {
      status: success ? "success" : "failure",
      executionId: $node["Assemble Provisioning Payload"]?.json?.executionId || `${success ? "onboard" : "failed"}-${Date.now()}`,
      employeeId: $node["Normalize Employee Data"].json.employeeId,
      email: $node["Normalize Employee Data"].json.email,
      failedNode: success ? null : (errorItem?.json?.node || "unknown"),
      error: success ? null : (errorItem?.json || null),
      timestamp: new Date().toISOString(),
      checks: {
        userInvited,
        assignedRoles,
        workspaceProvisioned,
        userProvisioned
      }
    }
  }
];
